using System; using System.Collections.Generic; using System.Linq; using StargateGalacticCommand.Core.Models;
namespace StargateGalacticCommand.Core.Services { public class SpaceCombatService { readonly ShipyardService _ships; readonly FactionModifierService _factions; readonly RankingService _ranking; public const double LootLimit=0.30; public const int RetaliationWindowHours=24; public SpaceCombatService(ShipyardService ships,FactionModifierService factions,RankingService ranking){_ships=ships;_factions=factions;_ranking=ranking;} public int CalculateDistance(PlayerBase a,PlayerBase b)=>a.PlanetSector.PlanetId==b.PlanetSector.PlanetId?Math.Max(1,Math.Abs(a.PlanetSector.Number-b.PlanetSector.Number)):25+Math.Abs(a.PlanetSector.PlanetId-b.PlanetSector.PlanetId)*10; public int CalculateFlightSeconds(int distance,ShipTypeDefinition d)=>Math.Max(60,(int)Math.Ceiling(distance*3600.0/d.Speed)); public SpaceCombatMission StartAttack(User attacker,PlayerBase origin,PlayerBase target,ShipType type,int count,IEnumerable<SpaceCombatMission> recent,PlayerProtectionStatus protection,DateTime now,IEnumerable<SpaceCombatMission> recentAttacksAgainstMe=null,bool alliancesUnderPact=false){ ValidateAttack(attacker,origin,target,type,count,recent,protection,now,recentAttacksAgainstMe,alliancesUnderPact); var d=_ships.Get(type); origin.Ships.Remove(type,count); var dist=CalculateDistance(origin,target); return new SpaceCombatMission{AttackerUserId=attacker.Id,AttackerUser=attacker,DefenderUserId=target.UserId,OriginBaseId=origin.Id,OriginBase=origin,TargetBaseId=target.Id,TargetBase=target,MissionType=FleetMissionType.Attack,ShipType=type,ShipCount=count,Distance=dist,StartedAtUtc=now,ArrivesAtUtc=now.AddSeconds(CalculateFlightSeconds(dist,d))};} public void ValidateAttack(User attacker,PlayerBase origin,PlayerBase target,ShipType type,int count,IEnumerable<SpaceCombatMission> recent,PlayerProtectionStatus protection,DateTime now,IEnumerable<SpaceCombatMission> recentAttacksAgainstMe=null,bool alliancesUnderPact=false){ if(attacker==null||origin==null||target==null)throw new ArgumentNullException(); if(origin.UserId!=attacker.Id)throw new InvalidOperationException("Nur eigene Basis kann starten."); if(origin.Id==target.Id||origin.UserId==target.UserId)throw new InvalidOperationException("Eigenangriffe sind nicht erlaubt."); if(alliancesUnderPact)throw new InvalidOperationException("Ein aktiver Nichtangriffspakt zwischen den Allianzen verhindert diesen Angriff."); if(count<1)throw new ArgumentOutOfRangeException("count"); var d=_ships.Get(type); if(!d.IsActive)throw new InvalidOperationException("Nur kleine und mittlere aktive Schiffstypen sind erlaubt."); if(origin.Ships.GetCount(type)<count)throw new InvalidOperationException("Nicht genug Schiffe verfügbar."); if(protection!=null&&protection.IsUnderBeginnerProtection(now))throw new InvalidOperationException("Ziel steht unter Anfängerschutz."); if(protection!=null&&protection.Score>0){ var ownScore=_ranking.CalculateBaseScore(origin); bool hasRetaliationRight=recentAttacksAgainstMe!=null&&recentAttacksAgainstMe.Any(m=>m.AttackerUserId==target.UserId&&m.DefenderUserId==attacker.Id&&m.CompletedAtUtc.HasValue&&m.CompletedAtUtc.Value>now.AddHours(-RetaliationWindowHours)); if(!hasRetaliationRight&&ownScore>protection.Score*5)throw new InvalidOperationException("Punktedifferenz-Schutz verhindert den Angriff."); } if(recent!=null&&recent.Any(m=>m.AttackerUserId==attacker.Id&&m.TargetBaseId==target.Id&&m.CompletedAtUtc.HasValue&&m.CompletedAtUtc.Value>now.AddHours(-1)))throw new InvalidOperationException("Angriffscooldown gegen diese Basis aktiv."); } public Report BuildIncomingAttackReport(SpaceCombatMission mission,DateTime now)=>new Report{UserId=mission.DefenderUserId,Title="Angriffswarnung: Flotte im Anflug",Body=$"Sensoren erfassen eine anfliegende Flotte auf {mission.TargetBase.Name}. Voraussichtliche Ankunft: {mission.ArrivesAtUtc:dd.MM.yyyy HH:mm} UTC. Die genaue Flottenstärke ist ohne Spionage nicht bekannt.",CreatedAtUtc=now}; public SpaceCombatReport Resolve(SpaceCombatMission m,User attacker,User defender,DateTime now){ if(m.CompletedAtUtc.HasValue)throw new InvalidOperationException("Mission ist abgeschlossen."); if(m.ArrivesAtUtc>now)throw new InvalidOperationException("Flotte ist noch unterwegs."); var ad=_ships.Get(m.ShipType); int aShips=m.ShipCount, dShips=TotalShips(m.TargetBase.Ships); double atk=(aShips*(10+ad.Cost.Energy/10.0)*(1+(attacker.ResearchLevels?.Hyperdrive??0)*0.05))+((attacker.ResearchLevels?.Bc304Tactics??0)+(attacker.ResearchLevels?.PrometheusEngineering??0)+(attacker.ResearchLevels?.WarlordAmbitions??0))*3; double ashield=aShips*(8+(attacker.ResearchLevels?.ShieldTechnology??0)*2); double dhull=Math.Max(20, m.TargetBase.BuildingLevels.CommandCenter*30 + m.TargetBase.BuildingLevels.HangarLandingZone*20); double def=((dShips*8 + m.TargetBase.BuildingLevels.CommandCenter*15)*_factions.GetDefenseMultiplier(defender.Faction)*(1+(defender.ResearchLevels?.ShieldTechnology??0)*0.05))+((defender.ResearchLevels?.IrisSecurityProtocols??0)+(defender.ResearchLevels?.HatakCommandStructure??0)+(defender.ResearchLevels?.HonorGuardProtocols??0))*3; int rounds=0; while(rounds<6&&atk>0&&def>0){rounds++; def-=Math.Max(1,atk-2); atk-=Math.Max(1,def/4);} bool won=atk>def; int attackerLosses=won?Math.Max(0,(int)Math.Ceiling(aShips*0.25)):aShips; int defenderLosses=won?Math.Min(dShips,Math.Max(1,(int)Math.Ceiling(dShips*0.5))):Math.Min(dShips,Math.Max(0,(int)Math.Ceiling(dShips*0.15))); RemoveAny(m.TargetBase.Ships,defenderLosses); int survivors=aShips-attackerLosses; if(survivors>0)m.OriginBase.Ships.Add(m.ShipType,survivors); var r=new SpaceCombatReport{SpaceCombatMission=m,UserId=m.AttackerUserId,CreatedAtUtc=now,Title="Kampfbericht: "+m.TargetBase.Name,AttackerWon=won,Rounds=Math.Max(1,rounds),AttackerLosses=attackerLosses,DefenderLosses=defenderLosses}; if(won) Loot(m.TargetBase.Resources,m.OriginBase.Resources,r); r.Body=$"Runden: {r.Rounds}. Angreifer {(won?"siegt":"verliert")}. Verluste Angreifer: {attackerLosses}, Verteidiger: {defenderLosses}. Beute: N {r.LootNaquadah}, T {r.LootTrinium}, V {r.LootSupplies}, E {r.LootEnergy}, P {r.LootPersonnel}. Hauptbasis bleibt bestehen."; m.CompletedAtUtc=now; return r;} public DebrisField CreateDebris(SpaceCombatMission m,SpaceCombatReport r,DateTime now)=>new DebrisField{PlayerBaseId=m.TargetBaseId,PlayerBase=m.TargetBase,Naquadah=(r.AttackerLosses+r.DefenderLosses)*20,Trinium=(r.AttackerLosses+r.DefenderLosses)*10,CreatedAtUtc=now}; static int TotalShips(BaseShips s)=>s.F302+s.SmallTransporter+s.SupplyShuttle+s.Teltak+s.AlkeshLightBomber+s.JaffaTransporter+s.CloakedTeltak+s.AgentTransporter+s.SmugglerTransporter+s.PirateFighter; static void RemoveAny(BaseShips s,int n){foreach(ShipType t in Enum.GetValues(typeof(ShipType))){var c=Math.Min(n,s.GetCount(t)); if(c>0)s.Remove(t,c); n-=c; if(n<=0)break;}} static int Take(int value){return (int)Math.Floor(value*LootLimit);} static void Loot(ResourceStock from,ResourceStock to,SpaceCombatReport r){r.LootNaquadah=Take(from.Naquadah); from.Naquadah-=r.LootNaquadah; r.LootTrinium=Take(from.Trinium); from.Trinium-=r.LootTrinium; r.LootSupplies=Take(from.Supplies); from.Supplies-=r.LootSupplies; r.LootEnergy=Take(from.Energy); from.Energy-=r.LootEnergy; r.LootPersonnel=Take(from.Personnel); from.Personnel-=r.LootPersonnel; to.Naquadah+=r.LootNaquadah;to.Trinium+=r.LootTrinium;to.Supplies+=r.LootSupplies;to.Energy+=r.LootEnergy;to.Personnel+=r.LootPersonnel;} } }
